// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";
import { ReentrancyGuard } from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import { Pausable } from "@openzeppelin/contracts/utils/Pausable.sol";
import { Address } from "@openzeppelin/contracts/utils/Address.sol";
import { IERC20 } from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import { SafeERC20 } from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

import "./interfaces/IDEXFactory.sol";
import "./interfaces/IDEXPair.sol";
import "./DEXPair.sol";
import "./LiquidityLocker.sol";

/**
 * @title DEXFactory
 * @dev Optimized DEX factory contract with core security features
 * - Basic liquidity locking functionality
 * - Advanced fee management and revenue tracking
 * - Emergency controls and security features
 * - Gas optimizations and best practices
 */
contract DEXFactory is IDEXFactory, Ownable, ReentrancyGuard, Pausable {
    using Address for address;
    using SafeERC20 for IERC20;
    
    // ============ STATE VARIABLES ============
    
    // Mapping from token pair to pair address
    mapping(address => mapping(address => address)) private _getPair;
    
    // Array of all pairs
    address[] public allPairs;
    
    // Fee configuration
    uint256 public feeRate = 30; // 0.3% (30 basis points)
    uint256 public constant FEE_DENOMINATOR = 10000;
    uint256 public constant MAX_FEE_RATE = 1000; // 10% maximum
    
    // Factory statistics
    uint256 public totalPairsCreated;
    
    // Emergency controls
    bool public emergencyStop;
    mapping(address => bool) public authorizedOperators;
    mapping(address => bool) public blacklistedAddresses;
    
    // Security configuration
    mapping(address => IDEXFactory.PoolSecurityConfig) public poolSecurityConfigs;
    
    // Enhanced access control (simplified)
    mapping(address => bool) public isManager;
    
    // Reference to LiquidityLocker
    LiquidityLocker public liquidityLocker;
    
    // ============ EVENTS ============
    
    event ManagerUpdated(address indexed manager, bool authorized);
    event BlacklistUpdated(address indexed account, bool blacklisted);
    
    // ============ MODIFIERS ============
    
    modifier notEmergencyStopped() {
        require(!emergencyStop, "DEX: EMERGENCY_STOP");
        _;
    }
    
    modifier onlyAuthorized() {
        require(
            msg.sender == owner() || 
            authorizedOperators[msg.sender] || 
            isManager[msg.sender],
            "DEX: NOT_AUTHORIZED"
        );
        _;
    }
    
    modifier onlyManager() {
        require(
            msg.sender == owner() || isManager[msg.sender],
            "DEX: MANAGER_ONLY"
        );
        _;
    }
    
    modifier notBlacklisted(address account) {
        require(!blacklistedAddresses[account], "DEX: BLACKLISTED");
        _;
    }
    
    // ============ CONSTRUCTOR ============
    
    constructor(address locker) Ownable(msg.sender) {
        require(locker != address(0), "INV_LOCKER");
        emergencyStop = false;
        liquidityLocker = LiquidityLocker(locker);
    }
    
    // ============ PAIR CREATION FUNCTIONS ============
    
    /**
     * @dev Create a new trading pair with security configuration
     */
    function createPair(
        address tokenA, 
        address tokenB, 
        PoolSecurityConfig calldata securityConfig
    ) 
        external 
        override
        whenNotPaused 
        notEmergencyStopped
        notBlacklisted(msg.sender)
        returns (address pair) 
    {
        require(tokenA != tokenB, "DEX: IDENTICAL_ADDRESSES");
        require(tokenA != address(0) && tokenB != address(0), "DEX: ZERO_ADDRESS");
        require(tokenA.code.length > 0 && tokenB.code.length > 0, "DEX: NOT_CONTRACT");
        
        (address token0, address token1) = tokenA < tokenB ? (tokenA, tokenB) : (tokenB, tokenA);
        require(_getPair[token0][token1] == address(0), "DEX: PAIR_EXISTS");
        
        // Create the pair contract using CREATE2 for deterministic addresses
        bytes memory bytecode = type(DEXPair).creationCode;
        bytes32 salt = keccak256(abi.encodePacked(token0, token1));
        
        assembly {
            pair := create2(0, add(bytecode, 0x20), mload(bytecode), salt)
        }
        
        require(pair != address(0), "DEX: CREATE2_FAILED");
        
        // Initialize the pair with security configuration
        IDEXPair(pair).initialize(token0, token1, securityConfig);
        
        // Store security configuration
        poolSecurityConfigs[pair] = securityConfig;
        
        // Update state
        _getPair[token0][token1] = pair;
        _getPair[token1][token0] = pair;
        allPairs.push(pair);
        totalPairsCreated++;
        
        emit PairCreated(token0, token1, pair, allPairs.length, block.timestamp, securityConfig);
    }
    
    /**
     * @dev Create a new trading pair with default security configuration
     */
    function createPair(address tokenA, address tokenB) 
        external 
        override
        whenNotPaused 
        notEmergencyStopped
        notBlacklisted(msg.sender)
        returns (address pair) 
    {
        IDEXFactory.PoolSecurityConfig memory defaultConfig = IDEXFactory.PoolSecurityConfig({
            emergencyStop: true
        });
        
        return this.createPair(tokenA, tokenB, defaultConfig);
    }
    
    // ============ SIMPLIFIED LIQUIDITY LOCKING FUNCTIONS ============
    
    /**
     * @dev Lock liquidity for a specified duration (delegated to LiquidityLocker)
     */
    function lockLiquidity(
        address pair,
        uint256 amount,
        uint256 lockDuration,
        string memory description
    ) external payable override {
        require(pair != address(0), "INV_PAIR");
        require(amount > 0, "INV_AMT");
        require(lockDuration > 0, "INV_DUR");
        require(lockDuration <= 365 days, "LONG");
        require(_getPair[IDEXPair(pair).token0()][IDEXPair(pair).token1()] == pair, "NFND");
        
        // Calculate lock fee
        uint256 lockFeeRate = feeRate;
        uint256 lockFee = (amount * lockFeeRate) / FEE_DENOMINATOR;
        
        // Handle fee payment
        if (msg.value > 0) {
            require(msg.value >= lockFee, "FEE");
            // Refund excess ETH
            if (msg.value > lockFee) {
                (bool success, ) = msg.sender.call{value: msg.value - lockFee}("");
                require(success, "REFND");
            }
        } else {
            // For basic locks, transfer LP tokens as fee
            require(
                IERC20(pair).transferFrom(msg.sender, address(this), lockFee),
                "FEE_TF"
            );
        }
        
        // Transfer remaining LP tokens to this contract
        uint256 remainingAmount = amount - lockFee;
        require(
            IERC20(pair).transferFrom(msg.sender, address(this), remainingAmount),
            "TF"
        );
        
        // Delegate to LiquidityLocker
        liquidityLocker.lockLiquidity(pair, msg.sender, remainingAmount, lockDuration, description, lockFee);
    }
    
    /**
     * @dev Unlock liquidity after lock period expires (delegated to LiquidityLocker)
     */
    function unlockLiquidity(address pair, uint256 lockIndex) external override {
        liquidityLocker.unlockLiquidity(pair, lockIndex, msg.sender);
    }
    
    // ============ TRADING FEE COLLECTION ============
    
    /**
     * @dev Collect trading fees from pairs (called by pair contracts)
     */
    function collectTradingFees(address pair, uint256 amount) 
        external 
        nonReentrant 
    {
        require(_getPair[IDEXPair(pair).token0()][IDEXPair(pair).token1()] == pair, "INV_PAIR");
        
        emit TradingFeeCollected(pair, amount, 0, block.timestamp);
    }
    
    // ============ VIEW FUNCTIONS ============
    
    /**
     * @dev Get pair address for token pair
     */
    function getPair(address tokenA, address tokenB) external view override returns (address pair) {
        (address token0, address token1) = tokenA < tokenB ? (tokenA, tokenB) : (tokenB, tokenA);
        pair = _getPair[token0][token1];
    }
    
    /**
     * @dev Get pair address (interface compliance)
     */
    function getPairAddress(address tokenA, address tokenB) external view returns (address) {
        return this.getPair(tokenA, tokenB);
    }
    
    /**
     * @dev Get all pairs length
     */
    function allPairsLength() external view override returns (uint256) {
        return allPairs.length;
    }
    
    /**
     * @dev Get fee denominator
     */
    function feeDenominator() external pure override returns (uint256) {
        return FEE_DENOMINATOR;
    }
    
    // ============ ADMIN FUNCTIONS ============
    
    /**
     * @dev Update fee rate (manager only)
     */
    function updateFeeRate(uint256 newFeeRate) external onlyManager {
        require(newFeeRate <= MAX_FEE_RATE, "DEX: FEE_TOO_HIGH");
        uint256 oldFee = feeRate;
        feeRate = newFeeRate;
        emit FeeUpdated(oldFee, newFeeRate, msg.sender);
    }
    
    /**
     * @dev Set emergency stop (manager only)
     */
    function setEmergencyStop(bool stopped) external onlyManager {
        emergencyStop = stopped;
        emit EmergencyStopUpdated(stopped, msg.sender);
    }
    
    /**
     * @dev Authorize/unauthorize operator (manager only)
     */
    function setAuthorizedOperator(address operator, bool authorized) external onlyManager {
        authorizedOperators[operator] = authorized;
        emit OperatorAuthorized(operator, authorized);
    }
    
    /**
     * @dev Set manager (owner only)
     */
    function setManager(address manager, bool authorized) external onlyOwner {
        isManager[manager] = authorized;
        emit ManagerUpdated(manager, authorized);
    }
    
    /**
     * @dev Blacklist/unblacklist address (manager only)
     */
    function setBlacklisted(address account, bool blacklisted) external onlyManager {
        blacklistedAddresses[account] = blacklisted;
        emit BlacklistUpdated(account, blacklisted);
    }
    
    /**
     * @dev Pause/unpause factory (manager only)
     */
    function pause() external onlyManager {
        _pause();
    }
    
    function unpause() external onlyManager {
        _unpause();
    }
    
    /**
     * @dev Withdraw collected fees (manager only)
     */
    function withdrawFees() external onlyManager {
        uint256 balance = address(this).balance;
        require(balance > 0, "DEX: NO_FEES");
        
        (bool success, ) = owner().call{value: balance}("");
        require(success, "DEX: WITHDRAWAL_FAILED");
    }
    
    /**
     * @dev Emergency function to recover stuck tokens (owner only)
     */
    function emergencyRecover(address token, address to, uint256 amount) external onlyOwner {
        if (token == address(0)) {
            (bool success, ) = to.call{value: amount}("");
            require(success, "DEX: ETH_TRANSFER_FAILED");
        } else {
            IERC20(token).safeTransfer(to, amount);
        }
    }

    function createPairWithLiquidity(
        address tokenA,
        address tokenB,
        uint256 amountA,
        uint256 amountB,
        bool shouldLockLiquidity,
        uint256 lockDuration,
        string memory lockDescription
    ) external pure returns (address, uint256) {
        revert("NOT_IMPLEMENTED");
    }
}

contracts/DEXFactoryMinimal.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./interfaces/IDEXPair.sol";
import "./DEXPair.sol";

contract DEXFactoryMinimal is Ownable {
    mapping(address => mapping(address => address)) public _getPair;
    address[] public allPairs;
    uint256 public totalPairsCreated;
    
    // Liquidity locker integration
    address public liquidityLocker;
    
    // Fixed fee rate (0.3% = 30 basis points)
    uint256 public constant FEE_RATE = 30; // 0.3%
    uint256 public constant FEE_DENOMINATOR = 10000;

    event PairCreated(address indexed token0, address indexed token1, address pair, uint256);
    event LiquidityLockerUpdated(address indexed oldLocker, address indexed newLocker);

    constructor(address _liquidityLocker) Ownable(msg.sender) {
        require(_liquidityLocker != address(0), "INV_LOCKER");
        liquidityLocker = _liquidityLocker;
    }

    function createPair(address tokenA, address tokenB) external returns (address pair) {
        require(tokenA != tokenB, "ID"); // Identical addresses
        require(tokenA != address(0) && tokenB != address(0), "ZA"); // Zero address
        (address token0, address token1) = tokenA < tokenB ? (tokenA, tokenB) : (tokenB, tokenA);
        require(_getPair[token0][token1] == address(0), "PC"); // Pair exists
        bytes memory bytecode = type(DEXPair).creationCode;
        bytes32 salt = keccak256(abi.encodePacked(token0, token1));
        assembly {
            pair := create2(0, add(bytecode, 0x20), mload(bytecode), salt)
        }
        require(pair != address(0), "C2F"); // CREATE2 failed
        IDEXPair(pair).initialize(token0, token1);
        _getPair[token0][token1] = pair;
        _getPair[token1][token0] = pair;
        allPairs.push(pair);
        totalPairsCreated++;
        emit PairCreated(token0, token1, pair, allPairs.length);
    }

    function getPair(address tokenA, address tokenB) external view returns (address pair) {
        (address token0, address token1) = tokenA < tokenB ? (tokenA, tokenB) : (tokenB, tokenA);
        pair = _getPair[token0][token1];
    }

    function allPairsLength() external view returns (uint256) {
        return allPairs.length;
    }
    
    // Liquidity locking functions
    function lockLiquidity(
        address pair,
        address user,
        uint256 amount,
        uint256 lockDuration,
        string memory description,
        uint256 lockFee
    ) external {
        require(liquidityLocker != address(0), "NO_LOCKER");
        // Delegate to liquidity locker
        (bool success, ) = liquidityLocker.call(
            abi.encodeWithSignature(
                "lockLiquidity(address,address,uint256,uint256,string,uint256)",
                pair, user, amount, lockDuration, description, lockFee
            )
        );
        require(success, "LOCK_FAILED");
    }
    
    function unlockLiquidity(address pair, uint256 lockIndex, address user) external {
        require(liquidityLocker != address(0), "NO_LOCKER");
        // Delegate to liquidity locker
        (bool success, ) = liquidityLocker.call(
            abi.encodeWithSignature(
                "unlockLiquidity(address,uint256,address)",
                pair, lockIndex, user
            )
        );
        require(success, "UNLOCK_FAILED");
    }
    
    // Admin function to update liquidity locker
    function setLiquidityLocker(address _liquidityLocker) external onlyOwner {
        require(_liquidityLocker != address(0), "INV_LOCKER");
        address oldLocker = liquidityLocker;
        liquidityLocker = _liquidityLocker;
        emit LiquidityLockerUpdated(oldLocker, _liquidityLocker);
    }
}

contracts/DEXFactoryV2.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./interfaces/IDEXPair.sol";
import "./DEXPair.sol";

contract DEXFactoryV2 is IDEXFactory, Ownable {
    mapping(address => mapping(address => address)) public _getPair;
    address[] public allPairs;
    uint256 public totalPairsCreated;
    
    // Liquidity locker integration
    address public liquidityLocker;
    
    // Configurable fee system
    uint256 public feeRate = 30; // 0.3% default (30 basis points)
    uint256 public constant FEE_DENOMINATOR = 10000;
    uint256 public constant MAX_FEE_RATE = 1000; // 10% max

    event PairCreated(address indexed token0, address indexed token1, address pair, uint256);
    event LiquidityLockerUpdated(address indexed oldLocker, address indexed newLocker);
    event FeeRateUpdated(uint256 oldFee, uint256 newFee);
    event InitialLiquidityLocked(address indexed pair, address indexed user, uint256 amount, uint256 lockDuration);

    constructor(address _liquidityLocker) Ownable(msg.sender) {
        require(_liquidityLocker != address(0), "INV_LOCKER");
        liquidityLocker = _liquidityLocker;
    }

    function createPair(address tokenA, address tokenB) external returns (address pair) {
        return _createPair(tokenA, tokenB);
    }
    
    function _createPair(address tokenA, address tokenB) internal returns (address pair) {
        require(tokenA != tokenB, "ID"); // Identical addresses
        require(tokenA != address(0) && tokenB != address(0), "ZA"); // Zero address
        (address token0, address token1) = tokenA < tokenB ? (tokenA, tokenB) : (tokenB, tokenA);
        require(_getPair[token0][token1] == address(0), "PC"); // Pair exists
        bytes memory bytecode = type(DEXPair).creationCode;
        bytes32 salt = keccak256(abi.encodePacked(token0, token1));
        assembly {
            pair := create2(0, add(bytecode, 0x20), mload(bytecode), salt)
        }
        require(pair != address(0), "C2F"); // CREATE2 failed
        IDEXPair(pair).initialize(token0, token1);
        _getPair[token0][token1] = pair;
        _getPair[token1][token0] = pair;
        allPairs.push(pair);
        totalPairsCreated++;
        emit PairCreated(token0, token1, pair, allPairs.length);
    }

    /**
     * @dev Create pair, add initial liquidity, and optionally lock it in one transaction
     * @param tokenA First token address
     * @param tokenB Second token address
     * @param amountA Amount of tokenA for initial liquidity
     * @param amountB Amount of tokenB for initial liquidity
     * @param shouldLockLiquidity Whether to lock the initial liquidity
     * @param lockDuration Duration to lock liquidity (if locking)
     * @param lockDescription Description for the lock (if locking)
     * @return pair The created pair address
     * @return liquidity The amount of LP tokens minted
     */
    function createPairWithLiquidity(
        address tokenA,
        address tokenB,
        uint256 amountA,
        uint256 amountB,
        bool shouldLockLiquidity,
        uint256 lockDuration,
        string memory lockDescription
    ) external returns (address pair, uint256 liquidity) {
        require(tokenA != tokenB, "ID"); // Identical addresses
        require(tokenA != address(0) && tokenB != address(0), "ZA"); // Zero address
        require(amountA > 0 && amountB > 0, "INV_AMOUNTS"); // Valid amounts
        
        // Create the pair
        pair = _createPair(tokenA, tokenB);
        
        // Transfer tokens from user to pair contract
        require(IERC20(tokenA).transferFrom(msg.sender, pair, amountA), "TF_A_FAILED");
        require(IERC20(tokenB).transferFrom(msg.sender, pair, amountB), "TF_B_FAILED");
        
        // Mint initial liquidity to the user
        liquidity = IDEXPair(pair).mint(msg.sender);
        require(liquidity > 0, "MINT_FAILED");
        
        // Lock liquidity if requested
        if (shouldLockLiquidity) {
            require(liquidityLocker != address(0), "NO_LOCKER");
            require(lockDuration > 0, "INV_DURATION");
            
            // Calculate lock fee (0.1% of LP tokens)
            uint256 lockFee = (liquidity * 10) / 10000; // 0.1%
            uint256 lockAmount = liquidity - lockFee;
            
            // Transfer LP tokens from user to factory for locking
            require(IERC20(pair).transferFrom(msg.sender, address(this), liquidity), "TF_LP_FAILED");
            
            // Lock the liquidity
            (bool success, ) = liquidityLocker.call(
                abi.encodeWithSignature(
                    "lockLiquidity(address,address,uint256,uint256,string,uint256)",
                    pair, msg.sender, lockAmount, lockDuration, lockDescription, lockFee
                )
            );
            require(success, "LOCK_FAILED");
            
            emit InitialLiquidityLocked(pair, msg.sender, lockAmount, lockDuration);
        }
    }

    function getPair(address tokenA, address tokenB) external view returns (address pair) {
        (address token0, address token1) = tokenA < tokenB ? (tokenA, tokenB) : (tokenB, tokenA);
        pair = _getPair[token0][token1];
    }
    
    function getPairAddress(address tokenA, address tokenB) external view returns (address) {
        return _getPair[tokenA][tokenB];
    }

    function allPairsLength() external view returns (uint256) {
        return allPairs.length;
    }
    
    // Enhanced liquidity locking with automatic initial liquidity lock
    function lockLiquidity(
        address pair,
        address user,
        uint256 amount,
        uint256 lockDuration,
        string memory description,
        uint256 lockFee
    ) external {
        require(liquidityLocker != address(0), "NO_LOCKER");
        // Delegate to liquidity locker
        (bool success, ) = liquidityLocker.call(
            abi.encodeWithSignature(
                "lockLiquidity(address,address,uint256,uint256,string,uint256)",
                pair, user, amount, lockDuration, description, lockFee
            )
        );
        require(success, "LOCK_FAILED");
    }
    
    // Special function for locking initial liquidity automatically
    function lockInitialLiquidity(
        address pair,
        address user,
        uint256 lockDuration,
        string memory description
    ) external {
        require(liquidityLocker != address(0), "NO_LOCKER");
        require(pair != address(0), "INV_PAIR");
        
        // Get the user's LP token balance
        uint256 lpBalance = IERC20(pair).balanceOf(user);
        require(lpBalance > 0, "NO_LP");
        
        // Calculate lock fee (0.1% of LP tokens)
        uint256 lockFee = (lpBalance * 10) / 10000; // 0.1%
        uint256 lockAmount = lpBalance - lockFee;
        
        // Transfer LP tokens from user to factory (user must approve first)
        require(IERC20(pair).transferFrom(user, address(this), lpBalance), "TF_FAILED");
        
        // Lock the liquidity
        (bool success, ) = liquidityLocker.call(
            abi.encodeWithSignature(
                "lockLiquidity(address,address,uint256,uint256,string,uint256)",
                pair, user, lockAmount, lockDuration, description, lockFee
            )
        );
        require(success, "LOCK_FAILED");
        
        emit InitialLiquidityLocked(pair, user, lockAmount, lockDuration);
    }
    
    function unlockLiquidity(address pair, uint256 lockIndex, address user) external {
        require(liquidityLocker != address(0), "NO_LOCKER");
        // Delegate to liquidity locker
        (bool success, ) = liquidityLocker.call(
            abi.encodeWithSignature(
                "unlockLiquidity(address,uint256,address)",
                pair, lockIndex, user
            )
        );
        require(success, "UNLOCK_FAILED");
    }
    
    // Admin functions
    function setLiquidityLocker(address _liquidityLocker) external onlyOwner {
        require(_liquidityLocker != address(0), "INV_LOCKER");
        address oldLocker = liquidityLocker;
        liquidityLocker = _liquidityLocker;
        emit LiquidityLockerUpdated(oldLocker, _liquidityLocker);
    }
    
    function setFeeRate(uint256 newFeeRate) public onlyOwner {
        require(newFeeRate <= MAX_FEE_RATE, "FEE_TOO_HIGH");
        uint256 oldFee = feeRate;
        feeRate = newFeeRate;
        emit FeeRateUpdated(oldFee, newFeeRate);
    }
    
    // View functions
    function getFeeRate() external view returns (uint256) {
        return feeRate;
    }
    
    function getFeeDenominator() external pure returns (uint256) {
        return FEE_DENOMINATOR;
    }
    
    function feeDenominator() external pure returns (uint256) {
        return FEE_DENOMINATOR;
    }
    
    function updateFeeRate(uint256 newFeeRate) external onlyOwner {
        setFeeRate(newFeeRate);
    }
    
    function setEmergencyStop(bool stopped) external onlyOwner {
        // This would be implemented if we add emergency stop functionality
        revert("NOT_IMPLEMENTED");
    }
    
    function setAuthorizedOperator(address operator, bool authorized) external onlyOwner {
        // This would be implemented if we add operator functionality
        revert("NOT_IMPLEMENTED");
    }
    
    function pause() external onlyOwner {
        // This would be implemented if we add pausable functionality
        revert("NOT_IMPLEMENTED");
    }
    
    function unpause() external onlyOwner {
        // This would be implemented if we add pausable functionality
        revert("NOT_IMPLEMENTED");
    }
    
    function withdrawFees() external onlyOwner {
        // This would be implemented if we add fee collection functionality
        revert("NOT_IMPLEMENTED");
    }
    
    function collectTradingFees(address pair, uint256 amount) external {
        // This would be implemented if we add fee collection functionality
        revert("NOT_IMPLEMENTED");
    }

    // Interface compliance: stub for createPair with security config
    function createPair(address tokenA, address tokenB, PoolSecurityConfig calldata securityConfig) external override returns (address pair) {
        // For now, just call the default createPair
        return this.createPair(tokenA, tokenB);
    }

    // Interface compliance: stub for lockLiquidity (old signature)
    function lockLiquidity(address pair, uint256 amount, uint256 lockDuration, string memory description) external override payable {
        revert("Use new lockLiquidity signature");
    }

    // Interface compliance: stub for unlockLiquidity (old signature)
    function unlockLiquidity(address pair, uint256 lockIndex) external override {
        revert("Use new unlockLiquidity signature");
    }
}

contracts/DEXPair.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "./interfaces/IDEXPair.sol";
import "./interfaces/IDEXFactory.sol";

/**
 * @title DEXPair
 * @dev Pair contract for trading two tokens using AMM model
 * Implements constant product formula: x * y = k
 * Supports per-pool security features
 */
contract DEXPair is IDEXPair, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;
    
    // Token addresses
    address public override token0;
    address public override token1;
    
    // Reserves
    uint112 private reserve0;
    uint112 private reserve1;
    uint32 private blockTimestampLast;
    
    // Factory reference
    address public override factory;
    
    // Price oracle
    uint256 public override price0CumulativeLast;
    uint256 public override price1CumulativeLast;
    
    // Liquidity tracking
    mapping(address => uint256) public override balanceOf;
    uint256 public override totalSupply;
    
    // Security configuration
    IDEXFactory.PoolSecurityConfig public securityConfig;
    
    // Timelock variables
    mapping(bytes32 => uint256) public timelockProposals;
    mapping(bytes32 => bool) public executedProposals;
    
    // Events
    event SecurityConfigUpdated(IDEXFactory.PoolSecurityConfig config);
    event TimelockProposalCreated(bytes32 indexed proposalId, address indexed proposer, uint256 executionTime);
    event TimelockProposalExecuted(bytes32 indexed proposalId);
    
    modifier onlyFactory() {
        require(msg.sender == factory, "DEXPair: FORBIDDEN");
        _;
    }
    
    modifier notEmergencyStopped() {
        // Emergency stop is handled at factory level
        _;
    }
    
    constructor() {
        factory = msg.sender;
    }
    
    // Private initializer
    function _initialize(address _token0, address _token1, IDEXFactory.PoolSecurityConfig memory _securityConfig) private {
        require(token0 == address(0), "DEXPair: ALREADY_INITIALIZED");
        token0 = _token0;
        token1 = _token1;
        securityConfig = _securityConfig;
        emit SecurityConfigUpdated(_securityConfig);
    }

    function initialize(address _token0, address _token1) external override {
        IDEXFactory.PoolSecurityConfig memory defaultConfig = IDEXFactory.PoolSecurityConfig({
            emergencyStop: true
        });
        _initialize(_token0, _token1, defaultConfig);
    }

    function initialize(address _token0, address _token1, IDEXFactory.PoolSecurityConfig calldata _securityConfig) external override onlyFactory {
        _initialize(_token0, _token1, _securityConfig);
    }
    
    /**
     * @dev Get current reserves (internal version)
     */
    function _getReserves() 
        internal 
        view 
        returns (uint112 _reserve0, uint112 _reserve1, uint32 _blockTimestampLast) 
    {
        _reserve0 = reserve0;
        _reserve1 = reserve1;
        _blockTimestampLast = blockTimestampLast;
    }

    /**
     * @dev Get current reserves (external version)
     */
    function getReserves() 
        external 
        view 
        override 
        returns (uint112 _reserve0, uint112 _reserve1, uint32 _blockTimestampLast) 
    {
        return _getReserves();
    }
    
    /**
     * @dev Update reserves and price oracle
     */
    function _update(uint256 balance0, uint256 balance1, uint112 _reserve0, uint112 _reserve1) private {
        require(balance0 <= type(uint112).max && balance1 <= type(uint112).max, "DEXPair: OVERFLOW");
        uint32 blockTimestamp = uint32(block.timestamp % 2**32);
        uint32 timeElapsed = blockTimestamp - blockTimestampLast;
        if (timeElapsed > 0 && _reserve0 != 0 && _reserve1 != 0) {
            price0CumulativeLast += uint256(UQ112x112.uqdiv(UQ112x112.encode(_reserve1), _reserve0)) * timeElapsed;
            price1CumulativeLast += uint256(UQ112x112.uqdiv(UQ112x112.encode(_reserve0), _reserve1)) * timeElapsed;
        }
        reserve0 = uint112(balance0);
        reserve1 = uint112(balance1);
        blockTimestampLast = blockTimestamp;
        emit Sync(reserve0, reserve1);
    }
    
    /**
     * @dev Add liquidity to the pool
     */
    function mint(address to) 
        external 
        override 
        nonReentrant 
        whenNotPaused 
        notEmergencyStopped
        returns (uint256 liquidity) 
    {
        (uint112 _reserve0, uint112 _reserve1,) = _getReserves();
        uint256 balance0 = IERC20(token0).balanceOf(address(this));
        uint256 balance1 = IERC20(token1).balanceOf(address(this));
        uint256 amount0 = balance0 - _reserve0;
        uint256 amount1 = balance1 - _reserve1;
        
        require(amount0 > 0 && amount1 > 0, "DEXPair: INSUFFICIENT_INPUT_AMOUNT");
        
        uint256 _totalSupply = totalSupply;
        if (_totalSupply == 0) {
            liquidity = sqrt(amount0 * amount1) - MINIMUM_LIQUIDITY;
            _mint(address(0), MINIMUM_LIQUIDITY); // permanently lock the first MINIMUM_LIQUIDITY tokens
        } else {
            require(_reserve0 > 0 && _reserve1 > 0, "DEXPair: INSUFFICIENT_RESERVES");
            liquidity = min((amount0 * _totalSupply) / _reserve0, (amount1 * _totalSupply) / _reserve1);
        }
        require(liquidity > 0, "DEXPair: INSUFFICIENT_LIQUIDITY_MINTED");
        require(liquidity <= type(uint256).max - totalSupply, "DEXPair: LIQUIDITY_TOO_LARGE");
        
        _mint(to, liquidity);
        _update(balance0, balance1, _reserve0, _reserve1);
    }
    
    /**
     * @dev Remove liquidity from the pool
     */
    function burn(address to) 
        external 
        override 
        nonReentrant 
        whenNotPaused 
        notEmergencyStopped
        returns (uint256 amount0, uint256 amount1) 
    {
        (uint112 _reserve0, uint112 _reserve1,) = _getReserves();
        address _token0 = token0;
        address _token1 = token1;
        uint256 balance0 = IERC20(_token0).balanceOf(address(this));
        uint256 balance1 = IERC20(_token1).balanceOf(address(this));
        uint256 liquidity = balanceOf[address(this)];
        
        uint256 _totalSupply = totalSupply;
        amount0 = (liquidity * balance0) / _totalSupply;
        amount1 = (liquidity * balance1) / _totalSupply;
        require(amount0 > 0 && amount1 > 0, "DEXPair: INSUFFICIENT_LIQUIDITY_BURNED");
        
        _burn(address(this), liquidity);
        IERC20(_token0).safeTransfer(to, amount0);
        IERC20(_token1).safeTransfer(to, amount1);
        balance0 = IERC20(_token0).balanceOf(address(this));
        balance1 = IERC20(_token1).balanceOf(address(this));
        
        _update(balance0, balance1, _reserve0, _reserve1);
    }
    
    /**
     * @dev Swap tokens
     */
    function swap(uint256 amount0Out, uint256 amount1Out, address to, bytes calldata data) 
        external 
        override 
        nonReentrant 
        whenNotPaused 
        notEmergencyStopped
    {
        require(amount0Out > 0 || amount1Out > 0, "DEXPair: INSUFFICIENT_OUTPUT_AMOUNT");
        (uint112 _reserve0, uint112 _reserve1,) = _getReserves();
        require(amount0Out < _reserve0 && amount1Out < _reserve1, "DEXPair: INSUFFICIENT_LIQUIDITY");
        
        uint256 balance0;
        uint256 balance1;
        {
            address _token0 = token0;
            address _token1 = token1;
            require(to != _token0 && to != _token1, "DEXPair: INVALID_TO");
            if (amount0Out > 0) IERC20(_token0).safeTransfer(to, amount0Out);
            if (amount1Out > 0) IERC20(_token1).safeTransfer(to, amount1Out);
            if (data.length > 0) IDEXCallee(to).dexCall(msg.sender, amount0Out, amount1Out, data);
            balance0 = IERC20(_token0).balanceOf(address(this));
            balance1 = IERC20(_token1).balanceOf(address(this));
        }
        
        uint256 amount0In = balance0 > _reserve0 - amount0Out ? balance0 - (_reserve0 - amount0Out) : 0;
        uint256 amount1In = balance1 > _reserve1 - amount1Out ? balance1 - (_reserve1 - amount1Out) : 0;
        require(amount0In > 0 || amount1In > 0, "DEXPair: INSUFFICIENT_INPUT_AMOUNT");
        {
            uint256 balance0Adjusted = balance0 * 1000 - amount0In * 3;
            uint256 balance1Adjusted = balance1 * 1000 - amount1In * 3;
            require(balance0Adjusted * balance1Adjusted >= uint256(_reserve0) * uint256(_reserve1) * (1000**2), "DEXPair: K");
        }
        
        _update(balance0, balance1, _reserve0, _reserve1);
    }
    
    /**
     * @dev Force reserves to match balances
     */
    function sync() external override nonReentrant {
        _update(IERC20(token0).balanceOf(address(this)), IERC20(token1).balanceOf(address(this)), reserve0, reserve1);
    }
    
    // ERC20 functions
    function _mint(address to, uint256 value) internal {
        require(totalSupply + value >= totalSupply, "DEXPair: OVERFLOW");
        require(balanceOf[to] + value >= balanceOf[to], "DEXPair: OVERFLOW");
        totalSupply += value;
        balanceOf[to] += value;
    }
    
    function _burn(address from, uint256 value) internal {
        balanceOf[from] -= value;
        totalSupply -= value;
    }
    
    // Utility functions
    function min(uint256 a, uint256 b) internal pure returns (uint256) {
        return a < b ? a : b;
    }
    
    function sqrt(uint256 y) internal pure returns (uint256 z) {
        if (y > 3) {
            z = y;
            uint256 x = y / 2 + 1;
            while (x < z) {
                z = x;
                x = (y / x + x) / 2;
            }
        } else if (y != 0) {
            z = 1;
        }
    }
    
    // Constants
    uint256 public constant override MINIMUM_LIQUIDITY = 10**3;
    
    // ERC20 state variables
    mapping(address => mapping(address => uint256)) public override allowance;
    
    // ERC20 functions
    function approve(address spender, uint256 value) external override returns (bool) {
        allowance[msg.sender][spender] = value;
        emit Approval(msg.sender, spender, value);
        return true;
    }
    
    function transfer(address to, uint256 value) external override returns (bool) {
        balanceOf[msg.sender] -= value;
        balanceOf[to] += value;
        emit Transfer(msg.sender, to, value);
        return true;
    }
    
    function transferFrom(address from, address to, uint256 value) external override returns (bool) {
        if (allowance[from][msg.sender] != type(uint256).max) {
            allowance[from][msg.sender] -= value;
        }
        balanceOf[from] -= value;
        balanceOf[to] += value;
        emit Transfer(from, to, value);
        return true;
    }

    // Missing ERC20 functions
    function name() external pure override returns (string memory) {
        return "DEX LP Token";
    }
    
    function symbol() external pure override returns (string memory) {
        return "LP";
    }
    
    function decimals() external pure override returns (uint8) {
        return 18;
    }

    // EIP-2612 permit functions
    bytes32 public constant override PERMIT_TYPEHASH = keccak256(
        "Permit(address owner,address spender,uint256 value,uint256 nonce,uint256 deadline)"
    );
    
    mapping(address => uint256) public override nonces;
    
    /**
     * @dev Get domain separator (internal version)
     */
    function _DOMAIN_SEPARATOR() internal view returns (bytes32) {
        return keccak256(
            abi.encode(
                keccak256("EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"),
                keccak256(bytes("DEX LP Token")),
                keccak256(bytes("1")),
                block.chainid,
                address(this)
            )
        );
    }

    /**
     * @dev Get domain separator (external version)
     */
    function DOMAIN_SEPARATOR() external view override returns (bytes32) {
        return _DOMAIN_SEPARATOR();
    }
    
    function permit(
        address owner,
        address spender,
        uint256 value,
        uint256 deadline,
        uint8 v,
        bytes32 r,
        bytes32 s
    ) external override {
        require(deadline >= block.timestamp, "DEXPair: EXPIRED");
        bytes32 structHash = keccak256(
            abi.encode(PERMIT_TYPEHASH, owner, spender, value, nonces[owner]++, deadline)
        );
        bytes32 hash = keccak256(
            abi.encodePacked("\x19\x01", _DOMAIN_SEPARATOR(), structHash)
        );
        address signer = ecrecover(hash, v, r, s);
        require(signer == owner, "DEXPair: INVALID_SIGNATURE");
        allowance[owner][spender] = value;
        emit Approval(owner, spender, value);
    }

    // Additional required functions
    function skim(address to) external override {
        address _token0 = token0;
        address _token1 = token1;
        IERC20(_token0).safeTransfer(to, IERC20(_token0).balanceOf(address(this)) - reserve0);
        IERC20(_token1).safeTransfer(to, IERC20(_token1).balanceOf(address(this)) - reserve1);
    }

    function kLast() external view override returns (uint256) {
        return uint256(reserve0) * uint256(reserve1);
    }
}

// Library for fixed-point arithmetic
library UQ112x112 {
    uint224 constant Q112 = 2**112;
    
    function encode(uint112 y) internal pure returns (uint224 z) {
        z = uint224(y) * Q112;
    }
    
    function uqdiv(uint224 x, uint112 y) internal pure returns (uint224 z) {
        z = x / uint224(y);
    }
}

contracts/DEXRouter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { ReentrancyGuard } from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import { Pausable } from "@openzeppelin/contracts/utils/Pausable.sol";
import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";
import { IERC20 } from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import { SafeERC20 } from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import { Address } from "@openzeppelin/contracts/utils/Address.sol";
import "./interfaces/IDEXFactory.sol";
import "./interfaces/IDEXPair.sol";

/**
 * @title DEXRouter
 * @dev Enhanced router contract for user-friendly DEX operations
 * - Advanced slippage protection and price impact calculation
 * - Rate limiting and anti-spam protection
 * - Enhanced swap functionality with multiple paths
 * - Improved error handling and gas optimizations
 * - Emergency controls and security features
 * - Support for flash swaps and advanced trading features
 */
contract DEXRouter is ReentrancyGuard, Pausable, Ownable {
    using SafeERC20 for IERC20;
    using Address for address;

    // Factory address
    address public immutable factory;
    
    // WETH address (for ETH swaps)
    address public immutable WETH;
    
    // Rate limiting
    mapping(address => uint256) public lastSwapTime;
    uint256 public constant SWAP_COOLDOWN = 30 seconds;
    
    // Slippage protection
    uint256 public defaultSlippageTolerance = 500; // 5% default
    uint256 public constant MAX_SLIPPAGE_TOLERANCE = 2000; // 20% maximum
    
    // Price impact protection
    uint256 public maxPriceImpact = 1000; // 10% maximum
    uint256 public constant MAX_PRICE_IMPACT = 5000; // 50% maximum
    
    // Emergency controls
    bool public emergencyStop;
    mapping(address => bool) public blacklistedTokens;
    mapping(address => bool) public whitelistedTokens;
    bool public whitelistEnabled;
    
    // Enhanced access control
    mapping(address => bool) public isManager;
    mapping(address => bool) public isOperator;
    
    // Events
    event SwapExactTokensForTokens(
        address indexed sender,
        uint256 amountIn,
        uint256 amountOutMin,
        address[] path,
        address indexed to,
        uint256 deadline,
        uint256 amountOut,
        uint256 priceImpact
    );
    
    event SwapTokensForExactTokens(
        address indexed sender,
        uint256 amountOut,
        uint256 amountInMax,
        address[] path,
        address indexed to,
        uint256 deadline,
        uint256 amountIn,
        uint256 priceImpact
    );
    
    event SwapExactETHForTokens(
        address indexed sender,
        uint256 amountIn,
        uint256 amountOutMin,
        address[] path,
        address indexed to,
        uint256 deadline,
        uint256 amountOut,
        uint256 priceImpact
    );
    
    event SwapTokensForExactETH(
        address indexed sender,
        uint256 amountOut,
        uint256 amountInMax,
        address[] path,
        address indexed to,
        uint256 deadline,
        uint256 amountIn,
        uint256 priceImpact
    );
    
    event SlippageToleranceUpdated(uint256 oldTolerance, uint256 newTolerance);
    event PriceImpactLimitUpdated(uint256 oldLimit, uint256 newLimit);
    event EmergencyStopUpdated(bool stopped);
    event TokenBlacklisted(address indexed token, bool blacklisted);
    event TokenWhitelisted(address indexed token, bool whitelisted);
    event WhitelistEnabled(bool enabled);

    constructor(address _factory, address _WETH) Ownable(msg.sender) {
        require(_factory != address(0), "Router: INVALID_FACTORY");
        require(_WETH != address(0), "Router: INVALID_WETH");
        factory = _factory;
        WETH = _WETH;
        emergencyStop = false;
        whitelistEnabled = false;
    }

    // Ensure the contract can receive ETH
    receive() external payable {
        assert(msg.sender == WETH); // Only accept ETH from WETH contract
    }

    // ============ MODIFIERS ============
    
    modifier notEmergencyStopped() {
        require(!emergencyStop, "Router: Emergency stop active");
        _;
    }
    
    modifier onlyManager() {
        require(
            msg.sender == owner() || isManager[msg.sender],
            "Router: Manager access required"
        );
        _;
    }
    
    modifier onlyAuthorized() {
        require(
            msg.sender == owner() || 
            isManager[msg.sender] || 
            isOperator[msg.sender],
            "Router: Not authorized"
        );
        _;
    }
    
    modifier rateLimited() {
        require(
            block.timestamp >= lastSwapTime[msg.sender] + SWAP_COOLDOWN,
            "Router: Rate limit exceeded"
        );
        _;
        lastSwapTime[msg.sender] = block.timestamp;
    }
    
    modifier validToken(address token) {
        require(token != address(0), "Router: Invalid token");
        require(!blacklistedTokens[token], "Router: Token blacklisted");
        if (whitelistEnabled) {
            require(whitelistedTokens[token], "Router: Token not whitelisted");
        }
        _;
    }

    // ============ SWAP FUNCTIONS ============

    /**
     * @dev Swap exact tokens for tokens with enhanced protection
     */
    function swapExactTokensForTokens(
        uint256 amountIn,
        uint256 amountOutMin,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external nonReentrant whenNotPaused notEmergencyStopped rateLimited returns (uint256[] memory amounts) {
        require(deadline >= block.timestamp, "Router: EXPIRED");
        require(path.length >= 2, "Router: INVALID_PATH");
        require(to != address(0), "Router: INVALID_TO");
        require(amountIn > 0, "Router: INSUFFICIENT_INPUT_AMOUNT");
        
        // Validate tokens
        for (uint256 i = 0; i < path.length; i++) {
            require(path[i] != address(0), "Router: Invalid token");
            require(!blacklistedTokens[path[i]], "Router: Token blacklisted");
            if (whitelistEnabled) {
                require(whitelistedTokens[path[i]], "Router: Token not whitelisted");
            }
        }
        
        amounts = getAmountsOut(amountIn, path);
        uint256 amountOut = amounts[amounts.length - 1];
        
        // Enhanced slippage protection
        uint256 slippageTolerance = _getSlippageTolerance(msg.sender);
        uint256 minAmountOut = amountOutMin > 0 ? amountOutMin : 
            (amountOut * (10000 - slippageTolerance)) / 10000;
        
        require(amountOut >= minAmountOut, "Router: INSUFFICIENT_OUTPUT_AMOUNT");
        
        // Calculate price impact
        uint256 priceImpact = _calculatePriceImpact(amountIn, path[0], amountOut, path[path.length - 1]);
        require(priceImpact <= maxPriceImpact, "Router: PRICE_IMPACT_TOO_HIGH");
        
        IERC20(path[0]).safeTransferFrom(msg.sender, address(this), amountIn);
        _swap(amounts, path, to);
        
        emit SwapExactTokensForTokens(
            msg.sender, 
            amountIn, 
            minAmountOut, 
            path, 
            to, 
            deadline, 
            amountOut, 
            priceImpact
        );
    }

    /**
     * @dev Swap tokens for exact tokens with enhanced protection
     */
    function swapTokensForExactTokens(
        uint256 amountOut,
        uint256 amountInMax,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external nonReentrant whenNotPaused notEmergencyStopped rateLimited returns (uint256[] memory amounts) {
        require(deadline >= block.timestamp, "Router: EXPIRED");
        require(path.length >= 2, "Router: INVALID_PATH");
        require(to != address(0), "Router: INVALID_TO");
        require(amountOut > 0, "Router: INSUFFICIENT_OUTPUT_AMOUNT");
        
        // Validate tokens
        for (uint256 i = 0; i < path.length; i++) {
            require(path[i] != address(0), "Router: Invalid token");
            require(!blacklistedTokens[path[i]], "Router: Token blacklisted");
            if (whitelistEnabled) {
                require(whitelistedTokens[path[i]], "Router: Token not whitelisted");
            }
        }
        
        amounts = getAmountsIn(amountOut, path);
        uint256 amountIn = amounts[0];
        
        require(amountIn <= amountInMax, "Router: EXCESSIVE_INPUT_AMOUNT");
        
        // Calculate price impact
        uint256 priceImpact = _calculatePriceImpact(amountIn, path[0], amountOut, path[path.length - 1]);
        require(priceImpact <= maxPriceImpact, "Router: PRICE_IMPACT_TOO_HIGH");
        
        IERC20(path[0]).safeTransferFrom(msg.sender, address(this), amountIn);
        _swap(amounts, path, to);
        
        emit SwapTokensForExactTokens(
            msg.sender, 
            amountOut, 
            amountInMax, 
            path, 
            to, 
            deadline, 
            amountIn, 
            priceImpact
        );
    }

    /**
     * @dev Swap exact ETH for tokens with enhanced protection
     */
    function swapExactETHForTokens(
        uint256 amountOutMin,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external payable nonReentrant whenNotPaused notEmergencyStopped rateLimited returns (uint256[] memory amounts) {
        require(deadline >= block.timestamp, "Router: EXPIRED");
        require(path.length >= 2, "Router: INVALID_PATH");
        require(path[0] == WETH, "Router: INVALID_PATH");
        require(to != address(0), "Router: INVALID_TO");
        require(msg.value > 0, "Router: INSUFFICIENT_INPUT_AMOUNT");
        
        // Validate tokens
        for (uint256 i = 0; i < path.length; i++) {
            require(path[i] != address(0), "Router: Invalid token");
            require(!blacklistedTokens[path[i]], "Router: Token blacklisted");
            if (whitelistEnabled) {
                require(whitelistedTokens[path[i]], "Router: Token not whitelisted");
            }
        }
        
        amounts = getAmountsOut(msg.value, path);
        uint256 amountOut = amounts[amounts.length - 1];
        
        // Enhanced slippage protection
        uint256 slippageTolerance = _getSlippageTolerance(msg.sender);
        uint256 minAmountOut = amountOutMin > 0 ? amountOutMin : 
            (amountOut * (10000 - slippageTolerance)) / 10000;
        
        require(amountOut >= minAmountOut, "Router: INSUFFICIENT_OUTPUT_AMOUNT");
        
        // Calculate price impact
        uint256 priceImpact = _calculatePriceImpact(msg.value, WETH, amountOut, path[path.length - 1]);
        require(priceImpact <= maxPriceImpact, "Router: PRICE_IMPACT_TOO_HIGH");
        
        // Wrap ETH to WETH
        IWETH(WETH).deposit{value: msg.value}();
        
        _swap(amounts, path, to);
        
        emit SwapExactETHForTokens(
            msg.sender, 
            msg.value, 
            minAmountOut, 
            path, 
            to, 
            deadline, 
            amountOut, 
            priceImpact
        );
    }

    /**
     * @dev Swap tokens for exact ETH with enhanced protection
     */
    function swapTokensForExactETH(
        uint256 amountOut,
        uint256 amountInMax,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external nonReentrant whenNotPaused notEmergencyStopped rateLimited returns (uint256[] memory amounts) {
        require(deadline >= block.timestamp, "Router: EXPIRED");
        require(path.length >= 2, "Router: INVALID_PATH");
        require(path[path.length - 1] == WETH, "Router: INVALID_PATH");
        require(to != address(0), "Router: INVALID_TO");
        require(amountOut > 0, "Router: INSUFFICIENT_OUTPUT_AMOUNT");
        
        // Validate tokens
        for (uint256 i = 0; i < path.length; i++) {
            require(path[i] != address(0), "Router: Invalid token");
            require(!blacklistedTokens[path[i]], "Router: Token blacklisted");
            if (whitelistEnabled) {
                require(whitelistedTokens[path[i]], "Router: Token not whitelisted");
            }
        }
        
        amounts = getAmountsIn(amountOut, path);
        uint256 amountIn = amounts[0];
        
        require(amountIn <= amountInMax, "Router: EXCESSIVE_INPUT_AMOUNT");
        
        // Calculate price impact
        uint256 priceImpact = _calculatePriceImpact(amountIn, path[0], amountOut, WETH);
        require(priceImpact <= maxPriceImpact, "Router: PRICE_IMPACT_TOO_HIGH");
        
        IERC20(path[0]).safeTransferFrom(msg.sender, address(this), amountIn);
        _swap(amounts, path, address(this));
        
        // Unwrap WETH to ETH
        IWETH(WETH).withdraw(amounts[amounts.length - 1]);
        
        // Transfer ETH to recipient
        (bool success,) = to.call{value: amounts[amounts.length - 1]}("");
        require(success, "Router: ETH_TRANSFER_FAILED");
        
        emit SwapTokensForExactETH(
            msg.sender, 
            amountOut, 
            amountInMax, 
            path, 
            to, 
            deadline, 
            amountIn, 
            priceImpact
        );
    }

    // ============ LIQUIDITY FUNCTIONS ============

    /**
     * @dev Add liquidity to a pair with enhanced protection
     */
    function addLiquidity(
        address tokenA,
        address tokenB,
        uint256 amountADesired,
        uint256 amountBDesired,
        uint256 amountAMin,
        uint256 amountBMin,
        address to,
        uint256 deadline
    ) external nonReentrant whenNotPaused notEmergencyStopped returns (uint256 amountA, uint256 amountB, uint256 liquidity) {
        require(deadline >= block.timestamp, "Router: EXPIRED");
        require(to != address(0), "Router: INVALID_TO");
        require(amountADesired > 0 && amountBDesired > 0, "Router: INSUFFICIENT_AMOUNTS");
        // Inline token validation for tokenA
        require(tokenA != address(0), "Router: Invalid token");
        require(!blacklistedTokens[tokenA], "Router: Token blacklisted");
        if (whitelistEnabled) {
            require(whitelistedTokens[tokenA], "Router: Token not whitelisted");
        }
        // Inline token validation for tokenB
        require(tokenB != address(0), "Router: Invalid token");
        require(!blacklistedTokens[tokenB], "Router: Token blacklisted");
        if (whitelistEnabled) {
            require(whitelistedTokens[tokenB], "Router: Token not whitelisted");
        }
        
        (amountA, amountB) = _addLiquidity(tokenA, tokenB, amountADesired, amountBDesired, amountAMin, amountBMin);
        address pair = IDEXFactory(factory).getPairAddress(tokenA, tokenB);
        
        IERC20(tokenA).safeTransferFrom(msg.sender, pair, amountA);
        IERC20(tokenB).safeTransferFrom(msg.sender, pair, amountB);
        
        liquidity = IDEXPair(pair).mint(to);
    }

    /**
     * @dev Remove liquidity from a pair with enhanced protection
     */
    function removeLiquidity(
        address tokenA,
        address tokenB,
        uint256 liquidity,
        uint256 amountAMin,
        uint256 amountBMin,
        address to,
        uint256 deadline
    ) external nonReentrant whenNotPaused notEmergencyStopped returns (uint256 amountA, uint256 amountB) {
        require(deadline >= block.timestamp, "Router: EXPIRED");
        require(to != address(0), "Router: INVALID_TO");
        require(liquidity > 0, "Router: INSUFFICIENT_LIQUIDITY");
        // Inline token validation for tokenA
        require(tokenA != address(0), "Router: Invalid token");
        require(!blacklistedTokens[tokenA], "Router: Token blacklisted");
        if (whitelistEnabled) {
            require(whitelistedTokens[tokenA], "Router: Token not whitelisted");
        }
        // Inline token validation for tokenB
        require(tokenB != address(0), "Router: Invalid token");
        require(!blacklistedTokens[tokenB], "Router: Token blacklisted");
        if (whitelistEnabled) {
            require(whitelistedTokens[tokenB], "Router: Token not whitelisted");
        }
        
        address pair = IDEXFactory(factory).getPairAddress(tokenA, tokenB);
        IDEXPair(pair).transferFrom(msg.sender, pair, liquidity);
        (amountA, amountB) = IDEXPair(pair).burn(to);
        
        require(amountA >= amountAMin, "Router: INSUFFICIENT_A_AMOUNT");
        require(amountB >= amountBMin, "Router: INSUFFICIENT_B_AMOUNT");
    }

    // ============ VIEW FUNCTIONS ============
    
    function getAmountsOut(uint256 amountIn, address[] calldata path) 
        public 
        view 
        returns (uint256[] memory amounts) 
    {
        require(path.length >= 2, "Router: INVALID_PATH");
        amounts = new uint256[](path.length);
        amounts[0] = amountIn;
        
        for (uint256 i; i < path.length - 1; i++) {
            (uint256 reserveIn, uint256 reserveOut,) = IDEXPair(IDEXFactory(factory).getPairAddress(path[i], path[i + 1])).getReserves();
            amounts[i + 1] = getAmountOut(amounts[i], reserveIn, reserveOut);
        }
    }

    function getAmountsIn(uint256 amountOut, address[] calldata path) 
        public 
        view 
        returns (uint256[] memory amounts) 
    {
        require(path.length >= 2, "Router: INVALID_PATH");
        amounts = new uint256[](path.length);
        amounts[amounts.length - 1] = amountOut;
        
        for (uint256 i = path.length - 1; i > 0; i--) {
            (uint256 reserveIn, uint256 reserveOut,) = IDEXPair(IDEXFactory(factory).getPairAddress(path[i - 1], path[i])).getReserves();
            amounts[i - 1] = getAmountIn(amounts[i], reserveIn, reserveOut);
        }
    }

    function getAmountOut(uint256 amountIn, uint256 reserveIn, uint256 reserveOut) 
        public 
        pure 
        returns (uint256 amountOut) 
    {
        require(amountIn > 0, "Router: INSUFFICIENT_INPUT_AMOUNT");
        require(reserveIn > 0 && reserveOut > 0, "Router: INSUFFICIENT_LIQUIDITY");
        
        uint256 amountInWithFee = amountIn * 997; // 0.3% fee
        uint256 numerator = amountInWithFee * reserveOut;
        uint256 denominator = (reserveIn * 1000) + amountInWithFee;
        amountOut = numerator / denominator;
    }

    function getAmountIn(uint256 amountOut, uint256 reserveIn, uint256 reserveOut) 
        public 
        pure 
        returns (uint256 amountIn) 
    {
        require(amountOut > 0, "Router: INSUFFICIENT_OUTPUT_AMOUNT");
        require(reserveIn > 0 && reserveOut > 0, "Router: INSUFFICIENT_LIQUIDITY");
        
        uint256 numerator = reserveIn * amountOut * 1000;
        uint256 denominator = (reserveOut - amountOut) * 997; // 0.3% fee
        amountIn = (numerator / denominator) + 1;
    }

    // ============ INTERNAL FUNCTIONS ============
    
    function _swap(uint256[] memory amounts, address[] memory path, address to) internal {
        for (uint256 i; i < path.length - 1; i++) {
            (address input, address output) = (path[i], path[i + 1]);
            (address token0,) = sortTokens(input, output);
            uint256 amountOut = amounts[i + 1];
            (uint256 amount0Out, uint256 amount1Out) = input == token0 ? (uint256(0), amountOut) : (amountOut, uint256(0));
            address to_ = i < path.length - 2 ? IDEXFactory(factory).getPairAddress(output, path[i + 2]) : to;
            IDEXPair(IDEXFactory(factory).getPairAddress(input, output)).swap(amount0Out, amount1Out, to_, "");
        }
    }

    function _addLiquidity(
        address tokenA,
        address tokenB,
        uint256 amountADesired,
        uint256 amountBDesired,
        uint256 amountAMin,
        uint256 amountBMin
    ) internal view returns (uint256 amountA, uint256 amountB) {
        if (IDEXFactory(factory).getPairAddress(tokenA, tokenB) == address(0)) {
            (amountA, amountB) = (amountADesired, amountBDesired);
        } else {
            (uint256 reserveA, uint256 reserveB,) = IDEXPair(IDEXFactory(factory).getPairAddress(tokenA, tokenB)).getReserves();
            if (reserveA == 0 && reserveB == 0) {
                (amountA, amountB) = (amountADesired, amountBDesired);
            } else {
                uint256 amountBOptimal = quote(amountADesired, reserveA, reserveB);
                if (amountBOptimal <= amountBDesired) {
                    require(amountBOptimal >= amountBMin, "Router: INSUFFICIENT_B_AMOUNT");
                    (amountA, amountB) = (amountADesired, amountBOptimal);
                } else {
                    uint256 amountAOptimal = quote(amountBDesired, reserveB, reserveA);
                    assert(amountAOptimal <= amountADesired);
                    require(amountAOptimal >= amountAMin, "Router: INSUFFICIENT_A_AMOUNT");
                    (amountA, amountB) = (amountAOptimal, amountBDesired);
                }
            }
        }
    }

    function quote(uint256 amountA, uint256 reserveA, uint256 reserveB) 
        public 
        pure 
        returns (uint256 amountB) 
    {
        require(amountA > 0, "Router: INSUFFICIENT_AMOUNT");
        require(reserveA > 0 && reserveB > 0, "Router: INSUFFICIENT_LIQUIDITY");
        amountB = (amountA * reserveB) / reserveA;
    }

    function sortTokens(address tokenA, address tokenB) 
        public 
        pure 
        returns (address token0, address token1) 
    {
        return tokenA < tokenB ? (tokenA, tokenB) : (tokenB, tokenA);
    }
    
    /**
     * @dev Calculate price impact of a swap
     */
    function _calculatePriceImpact(
        uint256 amountIn, 
        address tokenIn, 
        uint256 amountOut, 
        address tokenOut
    ) internal view returns (uint256) {
        // Get reserves for the pair
        address pair = IDEXFactory(factory).getPairAddress(tokenIn, tokenOut);
        if (pair == address(0)) return 0;
        
        (uint256 reserveIn, uint256 reserveOut,) = IDEXPair(pair).getReserves();
        if (reserveIn == 0 || reserveOut == 0) return 0;
        
        // Calculate price before and after swap
        uint256 priceBefore = (reserveOut * 1e18) / reserveIn;
        uint256 reserveInAfter = reserveIn + amountIn;
        uint256 reserveOutAfter = reserveOut - amountOut;
        uint256 priceAfter = (reserveOutAfter * 1e18) / reserveInAfter;
        
        // Calculate price impact
        if (priceBefore > priceAfter) {
            return ((priceBefore - priceAfter) * 10000) / priceBefore;
        }
        return 0;
    }
    
    /**
     * @dev Get slippage tolerance for user (can be customized per user)
     */
    function _getSlippageTolerance(address user) internal view returns (uint256) {
        // For now, return default slippage tolerance
        // This can be enhanced with user-specific settings
        return defaultSlippageTolerance;
    }

    // ============ ADMIN FUNCTIONS ============
    
    /**
     * @dev Update slippage tolerance (manager only)
     */
    function updateSlippageTolerance(uint256 newTolerance) external onlyManager {
        require(newTolerance <= MAX_SLIPPAGE_TOLERANCE, "Router: Tolerance too high");
        uint256 oldTolerance = defaultSlippageTolerance;
        defaultSlippageTolerance = newTolerance;
        emit SlippageToleranceUpdated(oldTolerance, newTolerance);
    }
    
    /**
     * @dev Update price impact limit (manager only)
     */
    function updatePriceImpactLimit(uint256 newLimit) external onlyManager {
        require(newLimit <= MAX_PRICE_IMPACT, "Router: Limit too high");
        uint256 oldLimit = maxPriceImpact;
        maxPriceImpact = newLimit;
        emit PriceImpactLimitUpdated(oldLimit, newLimit);
    }
    
    /**
     * @dev Set emergency stop (manager only)
     */
    function setEmergencyStop(bool stopped) external onlyManager {
        emergencyStop = stopped;
        emit EmergencyStopUpdated(stopped);
    }
    
    /**
     * @dev Set manager (owner only)
     */
    function setManager(address manager, bool authorized) external onlyOwner {
        isManager[manager] = authorized;
    }
    
    /**
     * @dev Set operator (manager only)
     */
    function setOperator(address operator, bool authorized) external onlyManager {
        isOperator[operator] = authorized;
    }
    
    /**
     * @dev Blacklist/unblacklist token (manager only)
     */
    function setTokenBlacklisted(address token, bool blacklisted) external onlyManager {
        blacklistedTokens[token] = blacklisted;
        emit TokenBlacklisted(token, blacklisted);
    }
    
    /**
     * @dev Whitelist/unwhitelist token (manager only)
     */
    function setTokenWhitelisted(address token, bool whitelisted) external onlyManager {
        whitelistedTokens[token] = whitelisted;
        emit TokenWhitelisted(token, whitelisted);
    }
    
    /**
     * @dev Enable/disable whitelist (manager only)
     */
    function setWhitelistEnabled(bool enabled) external onlyManager {
        whitelistEnabled = enabled;
        emit WhitelistEnabled(enabled);
    }

    /**
     * @dev Emergency functions
     */
    function emergencyWithdraw(address token, address to, uint256 amount) external onlyManager {
        IERC20(token).safeTransfer(to, amount);
    }

    function pause() external onlyManager {
        _pause();
    }

    function unpause() external onlyManager {
        _unpause();
    }
}

// WETH interface
interface IWETH {
    function deposit() external payable;
    function withdraw(uint256 amount) external;
}

